mapper.select:
SELECT id, file_id, owner_id, bind_type, bind_id, bind_status, bind_version,
       bound_at, unbound_at, created_at, updated_at
FROM bluenote_file.file_binding
WHERE file_id = #{fileId}
  AND bind_type = #{bindType}
  AND bind_id = #{bindId}

mapper.update:
UPDATE bluenote_file.file_binding
SET owner_id = #{entity.ownerId},
    bind_status = 'BOUND',
    bind_version = bind_version + 1,
    bound_at = #{entity.boundAt},
    unbound_at = NULL,
    updated_at = #{entity.updatedAt}
WHERE file_id = #{fileId}
  AND bind_type = #{bindType}
  AND bind_id = #{bindId}
